// components/fields/ColorPicker.tsx

import React from 'react';
import type {FieldValues} from 'react-hook-form';
import type {IColorPicker, UseFieldLogicElementProps} from "@lmb-it/kitsconcerto-types";
import {KitsInputColorPicker} from "../../../../_compat";

/**
 * Renders a color picker input.

 */
export const ColorPicker = <T extends FieldValues>({
                                                       element,
                                                       control,
                                                       getValues,
                                                       fieldLogic,
                                                   }: UseFieldLogicElementProps<T>) => {

    // 1. The central hook provides all the necessary state and resolved props.
    const {
        field,
        fieldState,
        label,
        isDisabled,
        isRequired,
        attached,
        style: elementStyle,
        slots,
    } = fieldLogic

    // 2. Cast the element to its specific type to access unique properties.
    const colorPickerElement = element as IColorPicker<T>;
    const {colorFormat, inline} = colorPickerElement;

    // 3. The component is now only responsible for rendering the UI.
    return (
        <KitsInputColorPicker
            // --- Core react-hook-form props ---
            {...field} // Spreads `onChange`, `onBlur`, `value`, `ref`

            // --- Resolved props from useFieldLogic ---
            id={field.name}
            label={label}
            disabled={isDisabled}
            required={isRequired}
            invalid={fieldState.invalid}
            errors={fieldState.error?.message}
            attached={attached}

            // --- Props from the element definition ---
            colorFormat={colorFormat}
            inline={inline}
            style={elementStyle?.input}
            containerStyle={elementStyle?.container}
            slots={slots}
        />
    );
};

export default ColorPicker;
